[BusinessEvents(classStr(ETGDMSIntDocumentAttachmentContract),
"ETG Purchase/ Sales agreement document attachment ",
    "This business event will trigger when the document is attached in purchase/ sales agreement.",
    ModuleAxapta::AccountsPayable)]
public  class ETGDMSIntDocumentAttachmentEventClass extends BusinessEventsBase
{

    private PurchAgreementHeader purchAgreementHeader;
    private SalesAgreementHeader salesAgreementHeader;
    private DocuRef docuRef;


}

Method.Source:
/// <summary>
/// Static factory method to instantiate the event class with a purchase agreement and document reference.
/// </summary>
/// <param name="_purchAgreementHeader">The purchase agreement header object.</param>
/// <param name="_docuRef">The attached document reference.</param>
/// <returns>A populated instance of ETGDMSIntDocumentAttachmentEventClass.</returns>
public static ETGDMSIntDocumentAttachmentEventClass newFromPurchAgreement(PurchAgreementHeader _purchAgreementHeader, DocuRef _docuRef)
{
    ETGDMSIntDocumentAttachmentEventClass businessEvent = new ETGDMSIntDocumentAttachmentEventClass();
    businessEvent.parmPurchAgreementHeader(_purchAgreementHeader);
    businessEvent.parmDocuRef(_docuRef);
    businessEvent.buildContract();
    return businessEvent;
}

/// <summary>
/// Static factory method to instantiate the event class with a SALES agreement and document reference.
/// </summary>
/// <param name="_salesAgreementHeader">The sales agreement header object.</param>
/// <param name="_docuRef">The attached document reference.</param>
/// <returns>A populated instance of ETGDMSIntDocumentAttachmentEventClass.</returns>
public static ETGDMSIntDocumentAttachmentEventClass newFromSalesAgreement(SalesAgreementHeader _salesAgreementHeader, DocuRef _docuRef)
{
    ETGDMSIntDocumentAttachmentEventClass businessEvent = new ETGDMSIntDocumentAttachmentEventClass();
    businessEvent.parmSalesAgreementHeader(_salesAgreementHeader);
    businessEvent.parmDocuRef(_docuRef);
    businessEvent.buildContract();
    return businessEvent;
}

/// <summary>
/// Private constructor to enforce controlled instantiation.
/// </summary>
private void new()
{
}

/// <summary>
/// Gets or sets the purchase agreement header for the business event.
/// </summary>
/// <param name="_purchAgreementHeader">Optional parameter to set the header.</param>
/// <returns>The current PurchAgreementHeader value.</returns>
private PurchAgreementHeader parmPurchAgreementHeader(PurchAgreementHeader _purchAgreementHeader = purchAgreementHeader)
{
    purchAgreementHeader = _purchAgreementHeader;
    return purchAgreementHeader;
}

/// <summary>
/// Gets or sets the purchase agreement header for the business event.
/// </summary>
/// <param name="_purchAgreementHeader">Optional parameter to set the header.</param>
/// <returns>The current PurchAgreementHeader value.</returns>
private SalesAgreementHeader parmSalesAgreementHeader(SalesAgreementHeader _salesAgreementHeader = salesAgreementHeader)
{
    salesAgreementHeader = _salesAgreementHeader;
    return salesAgreementHeader;
}

/// <summary>
/// Gets or sets the document reference for the business event.
/// </summary>
/// <param name="_docuRef">Optional parameter to set the document reference.</param>
/// <returns>The current DocuRef value.</returns>
private DocuRef parmDocuRef(DocuRef _docuRef = docuRef)
{
    docuRef = _docuRef;
    return docuRef;
}

/// <summary>
/// Builds the business event contract object with data from the purchase agreement and document reference.
/// </summary>
/// <returns>A BusinessEventsContract instance populated with relevant data.</returns>s

[Wrappable(true), Replaceable(true)]
public BusinessEventsContract buildContract()
{
    BusinessEventsContract contract;

    if (purchAgreementHeader.RecId)
    {
        contract = ETGDMSIntDocumentAttachmentContract::newFromPurchAgreement(purchAgreementHeader, docuRef);
    }
    else if (salesAgreementHeader.RecId)
    {
        contract = ETGDMSIntDocumentAttachmentContract::newFromSalesAgreement(salesAgreementHeader, docuRef);
    }
    return contract;
}
